using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class SchoolSettingsRepository(XmlStorageService storage) : BaseXmlRepository<SchoolSettings>(storage){ protected override string FileName=>"school-settings.xml"; public SchoolSettings? Get()=>GetAll().FirstOrDefault(); public void Save(SchoolSettings s)=>SaveAll(new List<SchoolSettings>{s}); }
